1: // Client-side PDF page-by-page text extractor using pdfjs-dist CDN worker
2: export async function extractTextPageByPage(
3:   file: File | Blob
4: ): Promise<{ pageNumber: number; text: string }[]> {
5:   // Dynamically import pdfjs-dist client-side to prevent SSR ReferenceErrors (DOMMatrix) during compile
6:   const pdfjsLib = await import('pdfjs-dist');
7:   
8:   // Configure worker using the local self-hosted public file to prevent network CDN issues
9:   pdfjsLib.GlobalWorkerOptions.workerSrc = "/pdf.worker.min.mjs";
10: 
11:   const arrayBuffer = await file.arrayBuffer();
12:   
13:   // Load the document
14:   const loadingTask = pdfjsLib.getDocument({ data: arrayBuffer });
15:   const pdf = await loadingTask.promise;
16:   const numPages = pdf.numPages;
17:   const pagesData: { pageNumber: number; text: string }[] = [];
18: 
19:   for (let i = 1; i <= numPages; i++) {
20:     try {
21:       const page = await pdf.getPage(i);
22:       const textContent = await page.getTextContent();
23:       
24:       // Combine text items on the page
25:       const pageText = textContent.items
26:         .map((item: any) => item.str || '')
27:         .join(' ');
28:         
29:       pagesData.push({
30:         pageNumber: i,
31:         text: pageText.trim()
32:       });
33:     } catch (err) {
34:       console.error(`Error parsing page ${i}:`, err);
35:       pagesData.push({
36:         pageNumber: i,
37:         text: ''
38:       });
39:     }
40:   }
41: 
42:   return pagesData;
43: }
